div></div></div></div></div></div></div></footer></div><script src="https://d3e54v103j8qbb.cloudfront.net/js/jquery-3.5.1.min.dc5e7f18c8.js?site=6841ddf8ace3d9d9facb14fd" type="text/javascript" integrity="sha256-9/aliU8dGd2tb6OSsuzixeV4y/faTqgFtohetphbbj0=" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.schunk.172ec51a511480e2.js" type="text/javascript" integrity="sha384-qU8s0hexa7230yNvRC7SOXbAhsCCiiSAtnmgEod8Ssr0OB50VGzzWLiPDvmaspsW" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.schunk.b35ad38f1af2d1dd.js" type="text/javascript" integrity="sha384-kPxhylkVGPto1495l5ywl0+XeOoRmw9z2/veWrv7DrZxLddZq3b5CSHy2Pbwu6QE" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.edf23106.7ffc1f3e33d51fa2.js" type="text/javascript" integrity="sha384-wicn3eL0bgoqEmw1FcBYHYixtBTtjwr4B1GcFI4Kf5QwoQyupq1wtEgCOlE9CsW3" crossorigin="anonymous"></script><script>
(function () {

  /* ================================
     1. UTM CAPTURE (СРАЗУ)
  ================================= */
  const TRACK_PARAMS = [
    "utm_source","utm_medium","utm_campaign",
    "utm_term","utm_content","matchtype",
    "device","creative","gclid"
  ];

  const params = new URLSearchParams(window.location.search);
  const hasUtm = TRACK_PARAMS.some(p => params.get(p));

  if (hasUtm) {
    // Есть UTM в URL — перезаписываем чисто
    TRACK_PARAMS.forEach(param => {
      const value = params.get(param);
      if (value) {
        localStorage.setItem(`lead_param_${param}`, value);
      } else {
        localStorage.removeItem(`lead_param_${param}`);
      }
    });

  } else {
    // Нет UTM в URL — проверяем localStorage
    const hasSavedUtm = TRACK_PARAMS.some(p => localStorage.getItem(`lead_param_${p}`));

    if (!hasSavedUtm) {
      // Нет нигде — пишем SEO / organic / direct
      const ref = document.referrer || "";
      let searchEngine   = "";
      let organicKeyword = "";
      let refDomain      = "";

      try {
        if (ref) {
          const refUrl = new URL(ref);
          refDomain    = refUrl.hostname.replace(/^www\./, "");

          const SEO_ENGINES = {
            "google.com":     "google",
            "bing.com":       "bing",
            "yahoo.com":      "yahoo",
            "duckduckgo.com": "duckduckgo",
            "yandex.ru":      "yandex",
            "yandex.com":     "yandex",
            "baidu.com":      "baidu"
          };

          for (const [domain, name] of Object.entries(SEO_ENGINES)) {
            if (refDomain.includes(domain)) {
              searchEngine   = name;
              organicKeyword = refUrl.searchParams.get("q")
                || refUrl.searchParams.get("p")
                || refUrl.searchParams.get("query")
                || "(not provided)";
              break;
            }
          }
        }
      } catch(e) {}

      if (searchEngine) {
        localStorage.setItem("lead_param_utm_source", searchEngine);
        localStorage.setItem("lead_param_utm_medium", "organic");
        if (organicKeyword) localStorage.setItem("lead_param_utm_term", organicKeyword);
      } else if (refDomain && !refDomain.includes(window.location.hostname)) {
        localStorage.setItem("lead_param_utm_source", refDomain);
        localStorage.setItem("lead_param_utm_medium", "referral");
      } else {
        localStorage.setItem("lead_param_utm_source", "(direct)");
        localStorage.setItem("lead_param_utm_medium", "(none)");
      }
    }
    // Если hasSavedUtm — ничего не трогаем (first-touch)
  }

  if (!localStorage.getItem("lead_param_landing_page")) {
    localStorage.setItem("lead_param_landing_page", window.location.pathname);
  }


  /* ================================
     2. HIDDEN FIELDS (DOM READY)
  ================================= */
  function injectHiddenFields(form) {
    [...TRACK_PARAMS, "landing_page"].forEach(param => {
      if (!form.querySelector(`input[name="${param}"]`)) {
        const input = document.createElement("input");
        input.type = "hidden";
        input.name = param;
        input.value = localStorage.getItem(`lead_param_${param}`) || "";
        form.appendChild(input);
      }
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    document.querySelectorAll("form").forEach(injectHiddenFields);
  });


  /* ================================
     3. LAZY SYSTEM INIT
  ================================= */
  let lazyLoaded = false;

  function initLazy() {
    if (lazyLoaded) return;
    lazyLoaded = true;

    initDate();
    initForms();
    loadZoho();
  }

  window.addEventListener('scroll', initLazy, { once: true });
  window.addEventListener('click', initLazy, { once: true });
  setTimeout(initLazy, 4000);


  /* ================================
     4. DATE SCRIPT (LAZY)
  ================================= */
  function initDate() {
    const now = new Date();
    const lastDayDate = new Date(now.getFullYear(), now.getMonth() + 1, 0);

    const monthNames = [
      'January','February','March','April','May','June',
      'July','August','September','October','November','December'
    ];

    document.querySelectorAll('[data-last-day]').forEach(el => {
      const format = el.getAttribute('data-last-day');

      let text = '';
      const m = lastDayDate.getMonth() + 1;
      const d = lastDayDate.getDate();
      const y = lastDayDate.getFullYear();

      if (format === 'us-short') {
        text = `${m}/${d}/${String(y).slice(-2)}`;
      } else if (format === 'long') {
        text = `${monthNames[lastDayDate.getMonth()]} ${d}, ${y}`;
      }

      el.textContent = text;
    });
  }


  /* ================================
     5. FORM + IP + GOOGLE SHEETS
  ================================= */
  function initForms() {

    let ipData = {};
    let ipLoaded = false;

    function fetchIP() {
      return fetch('https://ipapi.co/json/')
        .then(r => r.json())
        .then(data => {
          ipLoaded = true;
          ipData = data;
        })
        .catch(() => ipLoaded = true);
    }

    function waitIP(timeout = 800) {
      return Promise.race([
        fetchIP(),
        new Promise(res => setTimeout(res, timeout))
      ]);
    }

    document.querySelectorAll('form').forEach(form => {

      form.addEventListener('submit', function () {

        waitIP().then(() => {

          const formData = new FormData(form);

          formData.append('ip_address', ipData.ip || '');
          formData.append('geo_location', ipData.city || '');

          const body = new URLSearchParams(formData);

          fetch('https://script.google.com/macros/s/AKfycbyJGhNROpBI8TUkGn9RtdNtIDxNjxsI52kyHgBtDIUauSEWgzVIqCFPic0-chwjxNxU/exec', {
            method: 'POST',
            body,
            keepalive: true
          });

          fetch('https://script.google.com/macros/s/AKfycbwp7eg4fm8OZtiHLjAFrbNyPaSyDjZWmfTJyhkiAZ2UsWYmE6l7euH9K0RtdgODH44Rmg/exec', {
            method: 'POST',
            body,
            keepalive: true
          });

        });

      });

    });
  }


  /* ================================
     6. ZOHO (LAZY)
  ================================= */
  function loadZoho() {
    const script = document.createElement('script');
    script.src = "https://salesiq.zohopublic.com/widget?wc=siqfe34762ee44eb77120f2a13c55fed7c0984ca603ae60aafcaf2adda4331dc65a";
    script.defer = true;
    document.body.appendChild(script);
  }

})();
</script>

<!-- SCROLL STYLE -->
<style>
.scroll-block {
  overflow-y: auto;
  scrollbar-width: thin;
  scrollbar-color: #E79800 transparent;
}
.scroll-block::-webkit-scrollbar { width: 6px; }
.scroll-block::-webkit-scrollbar-thumb {
  background: #E79800;
  border-radius: 999px;
}
</style><script>
(() => {
  const $$ = (sel, root = document) => Array.from(root.querySelectorAll(sel));
  const $  = (sel, root = document) => root.querySelector(sel);

  const form = document.querySelector('[fs-list-element="filters"]');
  if (!form) return;

  const dropdowns = $$(".brand-filters_dropdown", form);
  const OPEN_CLASS = "is-open";

  // ✅ новые price поля
  const PRICE_FIELDS = ["price1", "price2", "price3", "price4", "price5"];

  // --- Prevent Webflow GET re-check ---
  form.setAttribute("autocomplete", "off");
  if (location.search) history.replaceState(null, "", location.pathname + location.hash);

  // --- Sync Webflow custom checkbox UI ---
  const syncWebflowUI = () => {
    $$('label.w-checkbox', form).forEach(lbl => {
      const inp = $('input[type="checkbox"][fs-list-field]', lbl);
      const custom = $(".w-checkbox-input", lbl);
      if (!inp || !custom) return;
      custom.classList.toggle("w--redirected-checked", inp.checked);
    });
  };

  // --- Sync UI when dropdown opens ---
  const syncOnOpen = () => {
    syncWebflowUI();
    requestAnimationFrame(syncWebflowUI);
    setTimeout(syncWebflowUI, 0);
  };

  const forceAllUnchecked = () => {
    const inputs = $$('input[type="checkbox"][fs-list-field]', form);
    inputs.forEach(inp => {
      inp.checked = false;
      inp.removeAttribute("checked");
    });
    syncWebflowUI();
  };

  // --- Dropdown open/close ---
  const closeAll = (except = null) => {
    dropdowns.forEach(dd => {
      if (except && dd === except) return;
      dd.classList.remove(OPEN_CLASS);
      const list = $(".brand_dropdown-list", dd);
      if (list) list.style.display = "none";
    });
  };

  const toggleDropdown = (dd) => {
    const list = $(".brand_dropdown-list", dd);
    if (!list) return;

    const isOpen = dd.classList.contains(OPEN_CLASS);

    if (isOpen) {
      dd.classList.remove(OPEN_CLASS);
      list.style.display = "none";
    } else {
      closeAll(dd);
      dd.classList.add(OPEN_CLASS);
      list.style.display = "block";
      syncOnOpen();
    }
  };

  dropdowns.forEach(dd => {
    const list = $(".brand_dropdown-list", dd);
    if (list) list.style.display = "none";

    const toggle = $(".brand_dropdown-toggle", dd);
    if (!toggle) return;

    toggle.style.cursor = "pointer";
    toggle.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      toggleDropdown(dd);
    });
  });

  document.addEventListener("click", () => closeAll());
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeAll();
  });

  // --- FS: checkbox values must match label text ---
  const ensureCheckboxValues = () => {
    $$('label.w-checkbox', form).forEach(lbl => {
      const input = $('input[type="checkbox"][fs-list-field]', lbl);
      if (!input) return;

      const txt = ($('.checkbox-label', lbl)?.textContent || "").trim();
      if (!txt) return;

      input.value = txt;
      input.setAttribute("value", txt);
    });
  };

  // --- Toggle text counter ---
  const initToggleDefaultText = (dd) => {
    const labelEl = $(".filter-btn-txt", dd);
    if (!labelEl) return;

    if (!labelEl.dataset.defaultText) {
      labelEl.dataset.defaultText = (labelEl.textContent || "")
        .replace(/\s*\(\d+\)\s*$/, "")
        .trim();

      labelEl.textContent = labelEl.dataset.defaultText;
    }
  };

  const countCheckedInDropdown = (dd, fields) => {
    return fields.reduce((sum, field) => {
      const checked = $$(`input[type="checkbox"][fs-list-field="${field}"]`, dd)
        .filter(i => i.checked).length;
      return sum + checked;
    }, 0);
  };

  const updateToggleLabel = (dd, fieldOrFields) => {
    const labelEl = $(".filter-btn-txt", dd);
    if (!labelEl) return;

    initToggleDefaultText(dd);
    const base = (labelEl.dataset.defaultText || "").trim();

    const fields = Array.isArray(fieldOrFields) ? fieldOrFields : [fieldOrFields];
    const checkedCount = countCheckedInDropdown(dd, fields);

    labelEl.textContent = checkedCount ? `${base} (${checkedCount})` : base;
  };

  const refreshAllToggles = () => {
    dropdowns.forEach(dd => {
      initToggleDefaultText(dd);

      // materials (как было)
      if ($(`input[fs-list-field="materials"]`, dd)) {
        updateToggleLabel(dd, "materials");
      }

      // ✅ price: если в этом дропдауне есть любой из price1..price5 — считаем суммой
      if (PRICE_FIELDS.some(f => $(`input[fs-list-field="${f}"]`, dd))) {
        updateToggleLabel(dd, PRICE_FIELDS);
      }
    });
  };

  form.addEventListener("change", (e) => {
    const t = e.target;
    if (!(t instanceof HTMLInputElement)) return;
    if (t.type !== "checkbox") return;

    syncWebflowUI();

    const dd = t.closest(".brand-filters_dropdown");
    if (!dd) return;

    const field = t.getAttribute("fs-list-field");

    if (field === "materials") {
      updateToggleLabel(dd, "materials");
    }

    // ✅ если клик по price1..price5 — обновляем счётчик Price Range
    if (field && PRICE_FIELDS.includes(field)) {
      updateToggleLabel(dd, PRICE_FIELDS);
    }
  });

  // --- Clear button ---
  const clearBtn = document.querySelector('[fs-list-element="clear"]');

  if (clearBtn) {
    clearBtn.addEventListener("click", () => {
      setTimeout(() => {
        forceAllUnchecked();
        closeAll();
        refreshAllToggles();
      }, 0);

      setTimeout(() => {
        forceAllUnchecked();
        refreshAllToggles();
      }, 60);
    });
  }

  // --- INIT ---
  ensureCheckboxValues();
  forceAllUnchecked();
  refreshAllToggles();
  syncWebflowUI();

  setTimeout(() => {
    ensureCheckboxValues();
    forceAllUnchecked();
    refreshAllToggles();
    syncWebflowUI();
  }, 200);
})();
</script>

<style>
.brand_dropdown-list { display: none; }
.brand-filters_dropdown.is-open .brand_dropdown-list { display: block; }
</style>
<script>
(() => {
  const $$ = (s, r=document) => Array.from(r.querySelectorAll(s));
  const $  = (s, r=document) => r.querySelector(s);

  const list = document.querySelector('[fs-list-element="list"]');
  if (!list) return;

  // ВАЖНО: вставляем empty в видимую обёртку коллекции, а не в сам list
  const dynList = list.closest('.w-dyn-list') || list.parentElement;
  if (!dynList) return;

  // создаём empty
  let empty = dynList.querySelector('.fs-empty-state');
  if (!empty) {
    empty = document.createElement('div');
    empty.className = 'fs-empty-state';
    empty.textContent = 'No results found';
    dynList.appendChild(empty);
  }

  // форс-стили, чтобы его точно было видно (если Webflow/IX2 гасит)
  const ensureEmptyVisibleStyles = () => {
    empty.style.display = 'none';
    empty.style.opacity = '1';
    empty.style.visibility = 'visible';
    empty.style.position = 'relative';
    empty.style.padding = '24px 0';
    empty.style.textAlign = 'center';
    empty.style.color = 'black';
  };
  ensureEmptyVisibleStyles();

  const hasVisibleItems = () => {
    // элементы коллекции обычно .w-dyn-item
    const items = $$('.w-dyn-item', dynList);
    // “видимый” = не display:none и есть в раскладке
    return items.some(el => el.offsetParent !== null);
  };

  const update = () => {
    const any = hasVisibleItems();

    // если список/обёртка скрыты — empty всё равно должен быть видим
    // поэтому empty живёт в dynList, не в list
    empty.style.display = any ? 'none' : 'block';
  };

  // отслеживаем любые изменения от Finsweet (style/class/children)
  const mo = new MutationObserver(() => update());
  mo.observe(dynList, { subtree: true, childList: true, attributes: true, attributeFilter: ['style','class'] });

  // также дергаем при смене фильтров
  const form = document.querySelector('[fs-list-element="filters"]');
  if (form) form.addEventListener('change', () => setTimeout(update, 0));

  // старт
  setTimeout(update, 0);
  setTimeout(update, 200);
})();
</script>


</body></html>
